import React, { useState } from 'react';

const PanelEditorEmpresas = () => {
  const [search, setSearch] = useState('');
  const [rubros, setRubros] = useState([
    { id: 1, nombre: 'Comercio' },
    { id: 2, nombre: 'Tecnología' },
    { id: 3, nombre: 'Turismo' },
    { id: 4, nombre: 'Educación' },
    { id: 5, nombre: 'Salud' },
  ]);

  const filteredRubros = rubros.filter(rubro => rubro.nombre.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="w-full min-h-screen bg-[#0d2d2a] text-[#f2f0df] px-4 py-6">
      <h1 className="text-center text-2xl font-bold text-[#9fa56c] mb-6">Panel de Edición</h1>

      <div className="flex flex-col md:flex-row justify-between items-center mb-4">
        <div className="text-[#9fa56c] text-lg font-semibold">DATOS</div>
        <div className="flex items-center gap-2 mt-2 md:mt-0">
          <input
            type="text"
            placeholder="Buscar rubro..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="bg-[#e1e4c5] text-black rounded px-4 py-2 w-full md:w-64 focus:outline-none"
          />
          <button className="bg-[#9fa56c] text-white rounded px-4 py-2">🔍</button>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full border-collapse bg-[#202020] text-white rounded shadow-md">
          <thead>
            <tr className="text-left bg-[#2b2b2b] text-[#e1e4c5]">
              <th className="p-3">Rubro</th>
              <th className="p-3">Nombre</th>
            </tr>
          </thead>
          <tbody>
            {filteredRubros.map((rubro) => (
              <tr key={rubro.id} className="hover:bg-[#353535]">
                <td className="p-3">{rubro.id}</td>
                <td className="p-3">
                  <input
                    type="text"
                    value={rubro.nombre}
                    onChange={(e) => {
                      const updatedRubros = rubros.map(r =>
                        r.id === rubro.id ? { ...r, nombre: e.target.value } : r
                      );
                      setRubros(updatedRubros);
                    }}
                    className="bg-[#e1e4c5] text-black px-2 py-1 rounded w-full"
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default PanelEditorEmpresas;
